package intent.AquaDev.aqua.modules.combat;

import events.listeners.EventPacket;
import net.minecraft.entity.Entity;
import net.minecraft.entity.EntityLivingBase;
import net.minecraft.network.EnumPacketDirection;
import net.minecraft.network.Packet;
import net.minecraft.network.play.server.S14PacketEntity;

public class Backtrack extends Module {
    // ... (fields, constructor, onEnable/onDisable) ...

    @Override
    public void onEvent(Event event) {
        if (event instanceof EventPacket) {
            EventPacket eventPacket = (EventPacket) event;
            if (eventPacket.getDirection() != EnumPacketDirection.CLIENTBOUND) return;

            Packet p = EventPacket.getPacket();

            // S14 ENTITY RELATIVE MOVE HANDLER
            if (p instanceof S14PacketEntity) {
                S14PacketEntity packet = (S14PacketEntity) EventPacket.getPacket();
                Entity entity1 = mc.theWorld.getEntityByID(packet.getEntityId());
                if (entity1 instanceof EntityLivingBase) {
                    EntityLivingBase entityLivingBase = (EntityLivingBase) entity1;
                    // Accumulate relative deltas for real position tracking
                    entityLivingBase.realPosX += packet.func_149062_c();  // dx
                    entityLivingBase.realPosY += packet.func_149061_d();  // dy
                    entityLivingBase.realPosZ += packet.func_149064_e();  // dz
                }
            }

            // Track S18 teleport (resets realPos to absolute)
            if (p instanceof S18PacketEntityTeleport) {
                S18PacketEntityTeleport packet = (S18PacketEntityTeleport) EventPacket.getPacket();
                Entity entity1 = mc.theWorld.getEntityByID(packet.getEntityId());
                if (entity1 instanceof EntityLivingBase) {
                    EntityLivingBase entityLivingBase = (EntityLivingBase) entity1;
                    entityLivingBase.realPosX = packet.getX();  // absolute
                    entityLivingBase.realPosY = packet.getY();
                    entityLivingBase.realPosZ = packet.getZ();
                }
            }

            // Buffer S14 for Backtrack replay
            this.addPackets(p, eventPacket);
        }
    }

    private boolean blockPacket(Packet packet) {
        // S14 is one of the primary packets stored in the backtrack buffer
        if (packet instanceof S32PacketConfirmTransaction) return true;
        if (packet instanceof S14PacketEntity) return true;
        if (packet instanceof S19PacketEntityHeadLook) return true;
        // ... other buffered packet types ...
        return false;
    }
}

