package net.minecraft.network.play.server;

public class S14PacketEntity implements Packet<INetHandlerPlayClient> {
    protected int entityId;
    protected byte posX, posY, posZ;  // relative deltas × 32
    protected byte yaw, pitch;
    protected boolean onGround;
    protected boolean rotating;  // true for S16/S17
    protected boolean moving;    // true for S15/S17

    public S14PacketEntity() {}
    public S14PacketEntity(int entityIdIn, boolean onGroundIn) {
        this.entityId = entityIdIn;
        this.onGround = onGroundIn;
    }

    public void processPacket(INetHandlerPlayClient handler) { handler.handleEntityMovement(this); }
    public int getEntityId() { return this.entityId; }
    public byte func_149062_c() { return this.posX; }  // dx
    public byte func_149061_d() { return this.posY; }  // dy
    public byte func_149064_e() { return this.posZ; }  // dz
    public byte getYaw() { return this.yaw; }
    public byte getPitch() { return this.pitch; }
    public boolean isMoving() { return this.moving; }
    public boolean isRotating() { return this.rotating; }
    public boolean getOnGround() { return this.onGround; }
}

